#include<bits/stdc++.h>
using namespace std;
long long a[2000010],dp[2000010];
int main()
{
    long long n,l,r;
    scanf("%lld%lld%lld",&n,&l,&r);
    for(long long i=0;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    memset(dp,-0x3f,sizeof(dp));
    dp[0]=0;
    deque<long long> q;
    for(long long i=l;i<=n+l;i++)
    {
        while(!q.empty()&&dp[q.back()]<=dp[i-l])
        {
            q.pop_back();
        }
        q.push_back(i-l);
        while(!q.empty()&&q.front()<i-r)
        {
            q.pop_front();
        }
        dp[min(n+1,i)]=max(dp[min(n+1,i)],dp[q.front()]+a[i]);
    }
    printf("%lld",dp[n+1]);
    return 0;
}
